// Fetches and caches docs/data/states.json (generated by
// scripts/build_states_json.py from state_distributions_summary.csv).

let cache = null;

export async function loadStatesData() {
  if (cache) return cache;
  const res = await fetch('./data/states.json');
  if (!res.ok) {
    throw new Error(`Failed to load states.json: ${res.status} ${res.statusText}`);
  }
  cache = await res.json();
  return cache;
}

// Convenience: build the {code, name} list for a <select>, pinned states first
// (in pinned order), then the remaining states alphabetically by name.
export function buildStateOptions(data) {
  const pinnedSet = new Set(data.pinned);
  const pinned = data.pinned.map((code) => ({ code, name: data.states[code].name }));
  const rest = Object.keys(data.states)
    .filter((code) => !pinnedSet.has(code))
    .map((code) => ({ code, name: data.states[code].name }))
    .sort((a, b) => a.name.localeCompare(b.name));
  return { pinned, rest };
}
